const express = require('express');
const axios = require('axios');
const app = express();
const port = process.env.PORT || 3000;

// Middleware to parse JSON and URL-encoded bodies
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// Webhook proxy endpoint
app.all('/proxy-webhook', async (req, res) => {
    // The target URL is expected as a query parameter
    const { targetUrl } = req.query;

    if (!targetUrl) {
        return res.status(400).json({ error: 'targetUrl query parameter is required.' });
    }

    // Basic URL validation
    if (!targetUrl.startsWith('http://') && !targetUrl.startsWith('https://')) {
        return res.status(400).json({ error: 'targetUrl must be a valid http(s) URL.' });
    }

    try {
        // Prepare headers for the outgoing request
        const headers = { ...req.headers };

        // Remove headers that should not be forwarded or are handled by axios
        delete headers['host'];
        delete headers['connection'];
        delete headers['content-length']; // Axios calculates this automatically
        delete headers['transfer-encoding']; // Axios handles this automatically

        // Configuration for the axios request
        const axiosConfig = {
            method: req.method, // Use the original request method (GET, POST, PUT, etc.)
            url: targetUrl,
            headers: headers,
            data: req.body, // Forward the original request body
            validateStatus: () => true, // Do not throw errors for 4xx/5xx responses
            responseType: 'arraybuffer' // Ensure binary data is handled correctly
        };

        const response = await axios(axiosConfig);

        // Set the status code from the target response
        res.status(response.status);

        // Forward all headers from the target response
        for (const headerName in response.headers) {
            // Exclude headers that Express handles or could cause issues
            if (!['transfer-encoding', 'content-length', 'connection', 'date'].includes(headerName.toLowerCase())) {
                res.set(headerName, response.headers[headerName]);
            }
        }

        // Forward the body from the target response
        res.send(response.data);

    } catch (error) {
        console.error('Error proxying webhook:', error.message);

        if (error.response) {
            // The request was made and the server responded with a status code
            // that falls out of the range of 2xx
            res.status(error.response.status).send(error.response.data);
        } else if (error.request) {
            // The request was made but no response was received
            res.status(502).json({ error: 'No response from target URL.', details: error.message });
        } else {
            // Something happened in setting up the request that triggered an Error
            res.status(500).json({ error: 'Failed to process proxy request.', details: error.message });
        }
    }
});

// Start the server
app.listen(port, () => {
    console.log(`Webhook proxy listening on port ${port}`);
});